# Steam Puck identity-passthrough map.
# Because the physical side (hidraw on the TV) already speaks USB-HID
# byte-for-byte, there is no shape translation -- the bridge gives us
# the exact wire bytes the kernel handed back from HID interrupt IN,
# and we forward them to the virtual USB interrupt IN endpoint.

[map]
id = steam_puck_identity
version = 1
virtual_device = steam_puck_usb
physical_device = steam_puck_via_puck

[usb.endpoints]
hid_in  = 0x81
hid_out = 0x01

[path.input.controller_to_virtual]
trigger = physical.read
# source_report = 0 means "accept any report id"; the report id arrives
# inline as the first byte of the bridge payload and is preserved through
# the identity copy below.
source_report = 0
destination_endpoint = 0x81
destination_report = 0
# Identity copy: take whatever the bridge handed us (up to 4096 bytes,
# the cmu_hidraw_bridge cap) and ferry it verbatim to the virtual EP.
op.1 = bytes.copy source[0..4095] -> destination[0..4095]
destination_length = 4096

[path.output.virtual_to_controller]
trigger = usb.endpoint.hid_out
source_endpoint = 0x01
source_report = 0
destination_report = 0
destination_length = 4096
op.1 = bytes.copy source[0..4095] -> destination[0..4095]

[path.control.feature_get]
trigger = usb.ep0.GET_REPORT
cache_on_connect = false
if_cached = respond_from_cache
if_missing = forward_to_bridge

[path.control.feature_set]
trigger = usb.ep0.SET_REPORT
cache_written_reports = false
if_unknown = forward_to_bridge

# === CTM Bridge advertise manifest ===
# Steam Puck is info-only in the overlay: no per-controller tweakable
# settings. The puck surfaces as up to 4 entries (one per HID slot) in
# the overlay; this advertise block is the same for all 4.
[advertise]
controller_name = Steam Controller (Puck)
vendor = Valve
rumble = false
leds = false
adaptive_triggers = false
haptics = false
audio_output = false
audio_input = false
audio_redirect = false
volume_control_speaker = false
volume_control_headphone = false
audio_route_modes =
latency_adjustable_ms = 0
battery = false
stop_sniff_rate = false
overlay_settings =
